+                    .collect(),
+            },
+            chunks,
+        };
+
+        let err = reconstruct_chunked_payload(&chunked).unwrap_err();
+        assert!(matches!(
+            err,
+            CheckpointChunkError::PayloadIntegrityMismatch { .. }
+        ));
+    }
